// src/utils/gclid.ts

/**
 * ===========================
 * GCLID Event Tracker Utility
 * ===========================
 *
 * 📌 PURPOSE:
 * This utility tracks user interactions (form submission, call click, etc.)
 * and attaches them to an active Google Ads GCLID session stored in localStorage.
 *
 * 🔍 WHY IT'S SEPARATE:
 * This file is **not a React component**.
 * It's a reusable utility that can be imported anywhere across your app.
 * It's designed to be called manually in response to user events (e.g. onClick, onSubmit).
 *
 * ✅ Pair this with:
 *   → `TrackGclid.tsx` — runs globally on page load to store gclid + first visit timestamp
 *
 * 🧠 Example use in a form submit handler:
 *   import { trackEvent } from "../utils/gclid";
 *   trackEvent("form");
 *
 * 🧠 Example use in a call-to-click:
 *   <a href="tel:+12085551234" onClick={() => trackEvent("call")}>Call Us</a>
 */

export function trackEvent(type: 'form' | 'call' | 'mobile_call' | 'none') {
  if (typeof window === 'undefined') return;

  const existing = localStorage.getItem('gclid_data');
  if (!existing) return;

  const data = JSON.parse(existing);
  data.events.push({ type, timestamp: Date.now() });
  localStorage.setItem('gclid_data', JSON.stringify(data));
}

export function getGclidData() {
  if (typeof window === 'undefined') return null;
  const data = localStorage.getItem('gclid_data');
  return data ? JSON.parse(data) : null;
}

export function clearGclidData() {
  localStorage.removeItem('gclid_data');
}
